import { Agent, BingSearchTool, AzureAISearchTool } from "@azure/ai-projects";

const agent = new Agent({
  name: "agentic-rag-agent",
  instructions: "Plan queries across sources and cite results",
  model: "gpt-4o",
  tools: [
    new BingSearchTool({ maxResults: 5 }),
    new AzureAISearchTool({
      endpoint: "https://your-search-service.search.windows.net",
      indexName: "enterprise-rag-index",
      apiKey: process.env.AZURE_SEARCH_KEY
    })
  ]
});

const thread = await agent.createThread();
const response = await agent.run(thread.id, "Find Q3 earnings data");

def extract_citations(response):
    citations = []
    for block in response.content:
        if hasattr(block, 'citations'):
            for citation in block.citations:
                citations.append({
                    'content': citation.content,
                    'title': citation.title,
                    'url': getattr(citation, 'url', None)
                })
    return citations

citations = extract_citations(response)
for c in citations:
    print(f"{c['title']}: {c['content'][:100]}...")

