from vex_sdk import VexClient
from azure.ai.projects import Agent
from azure.core.pipeline.policies import CustomPolicy

vex = VexClient(api_key="vex-api-key")

def vex_tool_policy(messages):
    for msg in messages:
        if msg.type == "tool_result":
            # Validate Bing results for freshness
            if "bing" in msg.name.lower():
                verdict = vex.verify({
                    "type": "source_freshness",
                    "content": msg.content,
                    "max_age_days": 30
                })
                if not verdict.passed:
                    msg.content = "[VEX BLOCKED: Outdated source]"
            # Check enterprise search for content vs metadata
            if "azureaisearch" in msg.name.lower():
                verdict = vex.verify({
                    "type": "content_extraction",
                    "content": msg.content,
                    "require": ["content", "title"]
                })
                if not verdict.passed:
                    msg.content = "[VEX BLOCKED: Missing content]"
    return messages

agent = Agent(..., additional_policies=[vex_tool_policy])

import { VexClient } from "vex-sdk";
import { Agent } from "@azure/ai-projects";

const vex = new VexClient({ apiKey: "vex-api-key" });

const vexMiddleware = async (messages: any[]) => {
  for (const msg of messages) {
    if (msg.type === "tool_result") {
      // Policy validation for tool outputs
      if (msg.name.toLowerCase().includes("bing")) {
        const verdict = await vex.verify({
          type: "source_freshness",
          content: msg.content,
          maxAgeDays: 30
        });
        if (!verdict.passed) {
          msg.content = "[VEX BLOCKED: Outdated source]";
        }
      }
      // Token limit monitoring
      const tokenCount = await vex.countTokens(msg.content);
      if (tokenCount > 128000) {
        msg.content = await vex.summarize(msg.content, { maxTokens: 32000 });
      }
    }
  }
  return messages;
};

const agent = new Agent({
  // ... config
  middleware: [vexMiddleware]
});
